SET NOCOUNT ON;
SET XACT_ABORT ON;

USE Mai_nwn;
GO

BEGIN TRY
    BEGIN TRANSACTION;

    -- Limpieza de datos existentes en tablas dependientes y la tabla Producto
    IF OBJECT_ID('dbo.DetalleVenta', 'U') IS NOT NULL
    BEGIN
        DELETE FROM dbo.DetalleVenta;
        PRINT 'Datos de dbo.DetalleVenta eliminados.';
    END;

    IF OBJECT_ID('dbo.Producto', 'U') IS NOT NULL
    BEGIN
        DELETE FROM dbo.Producto;
        PRINT 'Datos de dbo.Producto eliminados.';
    END;

    -- Activar IDENTITY_INSERT para poder especificar los valores de ProductoID
    SET IDENTITY_INSERT dbo.Producto ON;

    PRINT 'Iniciando inserción de 250 productos...';

    -- Desactivar IDENTITY_INSERT
    SET IDENTITY_INSERT dbo.Producto OFF;

    -- Reseed del contador de identidad para alinear con el último ID insertado
    DBCC CHECKIDENT ('dbo.Producto', RESEED, 250);

    COMMIT TRANSACTION;
    PRINT 'Script de seeding de datos para Producto completado exitosamente.';
END TRY
BEGIN CATCH
    IF @@TRANCOUNT > 0
        ROLLBACK TRANSACTION;
    DECLARE @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
    DECLARE @ErrorSeverity INT = ERROR_SEVERITY();
    DECLARE @ErrorState INT = ERROR_STATE();
    PRINT 'Error durante la ejecución del script de seeding: ' + @ErrorMessage;
    RAISERROR (@ErrorMessage, @ErrorSeverity, @ErrorState);
END CATCH;
GO
